import{_ as a,o,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"巴菲特致股东的信 — 1993年","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1993年/核心总结.md","filePath":"01_letters/1993年/核心总结.md"}'),e={name:"01_letters/1993年/核心总结.md"};function i(n,t,d,s,h,u){return o(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="巴菲特致股东的信-—-1993年" tabindex="-1">巴菲特致股东的信 — 1993年 <a class="header-anchor" href="#巴菲特致股东的信-—-1993年" aria-label="Permalink to &quot;巴菲特致股东的信 — 1993年&quot;">​</a></h1><p><strong>伯克希尔·哈撒韦公司</strong></p><p>致伯克希尔·哈撒韦公司股东：</p><p>1993年，我们的每股账面价值增长了14.3%。在过去29年里（即自现任管理层接手以来），账面价值已从19美元增长至8,852美元，年复合增长率为23.3%。</p><hr><h2 id="_1993年核心事件" tabindex="-1">1993年核心事件 <a class="header-anchor" href="#_1993年核心事件" aria-label="Permalink to &quot;1993年核心事件&quot;">​</a></h2><h3 id="_1-收购活动" tabindex="-1">1. 收购活动 <a class="header-anchor" href="#_1-收购活动" aria-label="Permalink to &quot;1. 收购活动&quot;">​</a></h3><p>1993年我们进行了几次重要收购：</p><ul><li><strong>怀特汽车公司（White Motor Corp旗下）</strong>：8月完成收购</li><li><strong>RC威利家居（RC Willey Home Furnishings）</strong>：12月完成</li><li><strong>布朗鞋业</strong>：从弗兰克·鲁尼手中收购</li></ul><h3 id="_2-股票投资策略" tabindex="-1">2. 股票投资策略 <a class="header-anchor" href="#_2-股票投资策略" aria-label="Permalink to &quot;2. 股票投资策略&quot;">​</a></h3><ul><li>出售部分 Capital Cities/ABC 股份，获$222.5M利润</li><li>巴菲特承认卖出Capital Cities是其投资生涯的最大错误之一</li></ul><h3 id="_3-保险业务" tabindex="-1">3. 保险业务 <a class="header-anchor" href="#_3-保险业务" aria-label="Permalink to &quot;3. 保险业务&quot;">​</a></h3><ul><li>浮存金成本为负（盈利）</li><li>超级巨灾保险业务表现不佳，亏损$119.6M</li><li>整体保险业务仍保持竞争力</li></ul><h3 id="_4-税务问题" tabindex="-1">4. 税务问题 <a class="header-anchor" href="#_4-税务问题" aria-label="Permalink to &quot;4. 税务问题&quot;">​</a></h3><ul><li>讨论了税务会计变化的影响</li><li>递延税项的新会计规则</li></ul><hr><h2 id="_1993年经典语录" tabindex="-1">1993年经典语录 <a class="header-anchor" href="#_1993年经典语录" aria-label="Permalink to &quot;1993年经典语录&quot;">​</a></h2><ol><li><p><strong>关于能力圈</strong>：</p><blockquote><p>&quot;对于大多数投资者来说重要的不是他们知道多少，而是他们如何现实地定义自己不知道什么。&quot;</p></blockquote></li><li><p><strong>关于安全边际</strong>：</p><blockquote><p>&quot;安全边际是投资成功的基石。&quot;</p></blockquote></li><li><p><strong>关于股票预测</strong>：</p><blockquote><p>&quot;股票预测者的唯一价值是让算命先生看起来不错。&quot;</p></blockquote></li></ol><hr><h2 id="投资组合-1993年底" tabindex="-1">投资组合（1993年底） <a class="header-anchor" href="#投资组合-1993年底" aria-label="Permalink to &quot;投资组合（1993年底）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>持股比例</th><th>市值</th></tr></thead><tbody><tr><td>可口可乐</td><td>7.2%</td><td>-</td></tr><tr><td>政府雇员保险公司(GEICO)</td><td>48.2%</td><td>-</td></tr><tr><td>大都会/ABC</td><td>18.1%</td><td>-</td></tr><tr><td>吉列</td><td>11.0%</td><td>-</td></tr></tbody></table><hr><h2 id="核心要点总结" tabindex="-1">核心要点总结 <a class="header-anchor" href="#核心要点总结" aria-label="Permalink to &quot;核心要点总结&quot;">​</a></h2><ol><li><strong>价值投资的本质</strong>：不是买&quot;便宜&quot;的股票，而是以合理价格购买优秀企业</li><li><strong>能力圈原则</strong>：只投资自己理解的企业</li><li><strong>时间的力量</strong>：长期持有优秀企业，复利增长</li><li><strong>浮存金优势</strong>：保险业务的&quot;零成本&quot;资金是核心竞争力</li><li><strong>管理层的选择</strong>：优秀的管理层是企业价值的关键</li></ol><hr><p>沃伦·E·巴菲特 董事会主席 1994年3月1日</p>',26)])])}const p=a(e,[["render",i]]);export{c as __pageData,p as default};
